import{_ as a,o as t,c as s,i}from"./chunks/framework.2KsE0g5C.js";const g=JSON.parse('{"title":"Versioning & Release Policy","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/versioning.md","filePath":"contributing/versioning.md"}'),n={name:"contributing/versioning.md"};function o(r,e,l,h,c,d){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="versioning-release-policy" tabindex="-1">Versioning &amp; Release Policy <a class="header-anchor" href="#versioning-release-policy" aria-label="Permalink to &quot;Versioning &amp; Release Policy&quot;">​</a></h1><p>The Cobalt Design System follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a> (semver) and uses <a href="https://github.com/changesets/changesets" target="_blank" rel="noreferrer">Changesets</a> to manage versioning and changelogs across the monorepo.</p><h2 id="fixed-lockstep-versioning" tabindex="-1">Fixed / Lockstep Versioning <a class="header-anchor" href="#fixed-lockstep-versioning" aria-label="Permalink to &quot;Fixed / Lockstep Versioning&quot;">​</a></h2><p>All publishable Cobalt packages share a single version number. When any package receives a changeset, <strong>all six packages</strong> bump to the same version:</p><ul><li><code>@cobalt/tokens</code></li><li><code>@cobalt/icons</code></li><li><code>@cobalt/components</code></li><li><code>@cobalt/react</code></li><li><code>@cobalt/vue</code></li><li><code>@cobalt/angular</code></li></ul><p>This is enforced by the <code>&quot;fixed&quot;</code> configuration in <code>.changeset/config.json</code>. Consumers can always assume that all <code>@cobalt/*</code> packages at the same version are compatible.</p><blockquote><p>The docs package (<code>@cobalt/docs</code>) is excluded from versioning — it is private and not published to npm.</p></blockquote><h2 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h2><p>Version numbers follow the <code>MAJOR.MINOR.PATCH</code> format:</p><table tabindex="0"><thead><tr><th>Increment</th><th>When to Use</th><th>Example</th></tr></thead><tbody><tr><td><strong>Major</strong></td><td>Breaking changes that require consumer action</td><td><code>2.0.0</code></td></tr><tr><td><strong>Minor</strong></td><td>New features that are backward-compatible</td><td><code>1.3.0</code></td></tr><tr><td><strong>Patch</strong></td><td>Bug fixes and non-functional improvements</td><td><code>1.2.4</code></td></tr></tbody></table><h2 id="what-constitutes-a-breaking-change" tabindex="-1">What Constitutes a Breaking Change <a class="header-anchor" href="#what-constitutes-a-breaking-change" aria-label="Permalink to &quot;What Constitutes a Breaking Change&quot;">​</a></h2><p>A change is considered <strong>breaking</strong> if it requires consumers to modify their code, markup, or configuration when upgrading. Specifically:</p><h3 id="breaking-major-version-bump" tabindex="-1">Breaking (Major Version Bump) <a class="header-anchor" href="#breaking-major-version-bump" aria-label="Permalink to &quot;Breaking (Major Version Bump)&quot;">​</a></h3><ul><li>Removing a public property, method, event, slot, or CSS custom property</li><li>Renaming a component tag (e.g., <code>co-dialog</code> to <code>co-modal</code>)</li><li>Changing the type or default value of a public property</li><li>Changing event detail shape or event names</li><li>Removing or renaming a CSS custom property (<code>--co-*</code>)</li><li>Changing the DOM structure in a way that breaks CSS selectors or slot behavior</li><li>Dropping support for a browser or Node.js version</li><li>Changing the module export structure of a package</li></ul><h3 id="non-breaking-minor-or-patch" tabindex="-1">Non-Breaking (Minor or Patch) <a class="header-anchor" href="#non-breaking-minor-or-patch" aria-label="Permalink to &quot;Non-Breaking (Minor or Patch)&quot;">​</a></h3><ul><li>Adding a new property, method, event, slot, or CSS custom property</li><li>Adding a new component variant</li><li>Fixing a bug that aligns behavior with documented expectations</li><li>Updating internal implementation without affecting the public API</li><li>Performance improvements</li><li>Adding new exports alongside existing ones</li></ul><blockquote><p><strong>Tip:</strong> When in doubt, treat a change as breaking. It&#39;s better to bump a major version unnecessarily than to break consumers unexpectedly.</p></blockquote><h2 id="changesets-workflow" tabindex="-1">Changesets Workflow <a class="header-anchor" href="#changesets-workflow" aria-label="Permalink to &quot;Changesets Workflow&quot;">​</a></h2><p>We use <a href="https://github.com/changesets/changesets" target="_blank" rel="noreferrer">Changesets</a> to track changes and automate version bumps and changelog generation.</p><h3 id="adding-a-changeset" tabindex="-1">Adding a Changeset <a class="header-anchor" href="#adding-a-changeset" aria-label="Permalink to &quot;Adding a Changeset&quot;">​</a></h3><p>After making changes, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> changeset</span></span></code></pre></div><p>You&#39;ll be prompted to:</p><ol><li><strong>Select affected packages</strong> — Choose which packages your change impacts</li><li><strong>Choose bump type</strong> — Major, minor, or patch for each package</li><li><strong>Write a summary</strong> — A human-readable description of the change</li></ol><p>This creates a markdown file in the <code>.changeset/</code> directory. Commit this file along with your code changes.</p><h3 id="convenience-commands" tabindex="-1">Convenience Commands <a class="header-anchor" href="#convenience-commands" aria-label="Permalink to &quot;Convenience Commands&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>pnpm changeset</code></td><td>Create a new changeset interactively</td></tr><tr><td><code>pnpm version:bump</code></td><td>Apply pending changesets — bumps all packages</td></tr><tr><td><code>pnpm version:check</code></td><td>Show pending changesets without applying them</td></tr><tr><td><code>pnpm release</code></td><td>Publish updated packages to npm</td></tr></tbody></table><h3 id="changeset-summary-guidelines" tabindex="-1">Changeset Summary Guidelines <a class="header-anchor" href="#changeset-summary-guidelines" aria-label="Permalink to &quot;Changeset Summary Guidelines&quot;">​</a></h3><p>Write summaries from the consumer&#39;s perspective:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#91CBFF;--shiki-dark-font-weight:bold;--shiki-light:#005CC5;--shiki-light-font-weight:bold;">---</span></span>
<span class="line"><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">&#39;@cobalt/components&#39;: minor</span></span>
<span class="line"><span style="--shiki-dark:#91CBFF;--shiki-dark-font-weight:bold;--shiki-light:#005CC5;--shiki-light-font-weight:bold;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">Added </span><span style="--shiki-dark:#91CBFF;--shiki-light:#005CC5;">\`loading\`</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;"> property to co-button to display a spinner and disable interactions while an async action is in progress.</span></span></code></pre></div><p>Keep summaries:</p><ul><li><strong>Concise</strong> — One to two sentences</li><li><strong>Consumer-focused</strong> — Describe what changed for the user, not the implementation detail</li><li><strong>Actionable</strong> — For breaking changes, include migration steps</li></ul><h2 id="release-cadence" tabindex="-1">Release Cadence <a class="header-anchor" href="#release-cadence" aria-label="Permalink to &quot;Release Cadence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Release Type</th><th>Frequency</th><th>Description</th></tr></thead><tbody><tr><td><strong>Patch</strong></td><td>As needed</td><td>Bug fixes are released as soon as they pass CI</td></tr><tr><td><strong>Minor</strong></td><td>Biweekly</td><td>New features are batched into scheduled releases</td></tr><tr><td><strong>Major</strong></td><td>Quarterly</td><td>Breaking changes are batched and coordinated with consumers</td></tr><tr><td><strong>Pre-release</strong></td><td>As needed</td><td>Alpha/beta releases for testing before stable</td></tr></tbody></table><h3 id="release-process" tabindex="-1">Release Process <a class="header-anchor" href="#release-process" aria-label="Permalink to &quot;Release Process&quot;">​</a></h3><ol><li>The Changesets GitHub Action opens a <strong>Version Packages</strong> PR automatically when changesets accumulate on <code>main</code></li><li>The core team reviews the PR, verifying version bumps and changelog entries</li><li>Merging the PR triggers the publish pipeline, which publishes updated packages to npm</li><li>Release notes are published with the GitHub release</li></ol><h2 id="pre-release-channels" tabindex="-1">Pre-release Channels <a class="header-anchor" href="#pre-release-channels" aria-label="Permalink to &quot;Pre-release Channels&quot;">​</a></h2><p>For testing unstable features, we maintain pre-release channels:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Install a beta version</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> add</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components@beta</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"># Install a specific pre-release</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">pnpm</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> add</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> @cobalt/components@3.0.0-beta.1</span></span></code></pre></div><p>Pre-release versions follow the pattern <code>{version}-{channel}.{number}</code> (e.g., <code>3.0.0-beta.1</code>).</p><h2 id="deprecation-policy" tabindex="-1">Deprecation Policy <a class="header-anchor" href="#deprecation-policy" aria-label="Permalink to &quot;Deprecation Policy&quot;">​</a></h2><p>When a component, property, or API is slated for removal:</p><ol><li><strong>Announce deprecation</strong> — Mark the API as deprecated in the current minor release with <code>@deprecated</code> JSDoc tags and console warnings</li><li><strong>Provide migration path</strong> — Document the recommended alternative in the deprecation notice and changelog</li><li><strong>Minimum notice period</strong> — Deprecated APIs remain available for at least <strong>two major release cycles</strong> (roughly 6 months)</li><li><strong>Remove in major release</strong> — The deprecated API is removed in the next planned major version</li></ol><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-dark-high-contrast github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;">/**</span></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"> * </span><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">@deprecated</span><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"> Use \`variant\` instead. Will be removed in v4.0.</span></span>
<span class="line"><span style="--shiki-dark:#BDC4CC;--shiki-light:#6A737D;"> */</span></span>
<span class="line"><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">@</span><span style="--shiki-dark:#DBB7FF;--shiki-light:#6F42C1;">property</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">({ type: String })</span></span>
<span class="line"><span style="--shiki-dark:#FFB757;--shiki-light:#6F42C1;">type</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">: string </span><span style="--shiki-dark:#FF9492;--shiki-light:#D73A49;">=</span><span style="--shiki-dark:#ADDCFF;--shiki-light:#032F62;"> &#39;primary&#39;</span><span style="--shiki-dark:#F0F3F6;--shiki-light:#24292E;">;</span></span></code></pre></div><blockquote><p><strong>Note:</strong> Deprecated features continue to work and receive critical bug fixes during the notice period. They will not receive new features or enhancements.</p></blockquote>`,45)])])}const u=a(n,[["render",o]]);export{g as __pageData,u as default};
